package com.tidex.mobile.meshimport android.Manifestimport android.annotation.SuppressLintimport android.content.Contextimport android.content.pm.PackageManagerimport androidx.core.content.ContextCompatimport com.google.android.gms.location.FusedLocationProviderClientimport com.google.android.gms.location.LocationServicesimport com.google.android.gms.location.Priorityimport kotlinx.coroutines.suspendCancellableCoroutineimport kotlin.coroutines.resumeimport kotlin.coroutines.resumeWithExceptionclass LocationProvider(context: Context) {    private val fusedClient: FusedLocationProviderClient =        LocationServices.getFusedLocationProviderClient(context)    fun hasLocationPermission(context: Context): Boolean {        return ContextCompat.checkSelfPermission(            context,            Manifest.permission.ACCESS_FINE_LOCATION        ) == PackageManager.PERMISSION_GRANTED    }    @SuppressLint("MissingPermission")    suspend fun getCurrentLocation(context: Context): Pair<Double, Double> {        if (!hasLocationPermission(context)) {            throw SecurityException("ACCESS_FINE_LOCATION permission is required")        }        return suspendCancellableCoroutine { cont ->            fusedClient.getCurrentLocation(Priority.PRIORITY_HIGH_ACCURACY, null)                .addOnSuccessListener { location ->                    if (location == null) {                        cont.resumeWithException(IllegalStateException("Location unavailable"))                    } else {                        cont.resume(location.latitude to location.longitude)                    }                }                .addOnFailureListener { err ->                    cont.resumeWithException(err)                }        }    }}